### 4.2 Transaction with `withClient`

```js
import { withClient } from './db.js';

async function transferFunds(fromId, toId, amount) {
  return await withClient(async (client) => {
    try {
      await client.query('BEGIN');

      const { rows: [from] } = await client.query(
        'SELECT balance FROM accounts WHERE id = $1 FOR UPDATE',
        [fromId]
      );
      if (from.balance < amount) throw new Error('Insufficient funds');

      await client.query(
        'UPDATE accounts SET balance = balance - $1 WHERE id = $2',
        [amount, fromId]
      );
      await client.query(
        'UPDATE accounts SET balance = balance + $1 WHERE id = $2',
        [amount, toId]
      );

      await client.query('COMMIT');
      return { success: true };
    } catch (err) {
      await client.query('ROLLBACK');
      console.error('Transaction failed', err);
      throw err;
    }
  });
}
```

> **Tip** – If you need a *statement timeout* for every query, set the `statement_timeout` in the pool’s `options` or use a wrapper that injects it automatically.

