Below is a clean, `async/await`‑based rewrite of the original callback style.  
The new `getUser` returns a **Promise** (so callers can `await` it or use `.then/.catch`).  
If you’re still using the old callback API, you can keep a thin wrapper that forwards the result, but the core logic is now promise‑centric.

```js
// 1️⃣  Import the promisified version of your DB client
//     (e.g. mysql2/promise, pg, knex, etc.)
const db = require('./db');          // <-- your DB module
// If your client only offers callbacks, promisify it:
const { promisify } = require('util');
const queryAsync = promisify(db.query).bind(db);

// 2️⃣  Async/await implementation
/**
 * Fetch a user by ID.
 *
 * @param {number|string} id - The user’s primary key.
 * @returns {Promise<Object>}  The user row.
 * @throws {Error}            If the query fails or the user is not found.
 */
async function getUser(id) {
  // `queryAsync` returns a Promise that resolves to the rows array.
  const rows = await queryAsync('SELECT * FROM users WHERE id = ?', [id]);

  // If the array is empty → user not found
  if (!rows.length) {
    throw new Error('Not found');
  }

  // Return the first (and only) row
  return rows[0];
}

// 3️⃣  Usage examples

// a) Using async/await
(async () => {
  try {
    const user = await getUser(42);
    console.log('User:', user);
  } catch (err) {
    console.error('Error fetching user:', err.message);
  }
})();

// b) Using Promise chaining
getUser(42)
  .then(user => console.log('User:', user))
  .catch(err => console.error('Error fetching user:', err.message));
```

### Why this is better

| Old style | New style |
|-----------|-----------|
| Callback hell, hard to read | Linear, top‑to‑bottom flow |
| Error handling via `if (err) return callback(err)` | `try/catch` or `.catch` on the returned Promise |
| Hard to compose multiple async steps | `await` lets you chain calls naturally |
| Hard to test (mocking callbacks) | Return a Promise → easier to stub/mock |

### If you still need the callback signature

If some legacy code still expects `getUser(id, callback)`, you can keep a thin wrapper:

```js
function getUserWithCallback(id, callback) {
  getUser(id)
    .then(user => callback(null, user))
    .catch(err => callback(err));
}
```

But for new code, just use the async/await version.

```js
// If db.query uses callbacks, promisify it once
const { promisify } = require('util');
const query = promisify(db.query).bind(db);

async function getUser(id) {
  const rows = await query('SELECT * FROM users WHERE id = ?', [id]);

  if (!rows.length) throw new Error('Not found');

  return rows[0];
}

// Usage
// getUser(42)
//   .then(user => console.log(user))
//   .catch(err => console.error(err));
```

